for i in range(len(nums)):
    for j in range(i + 1, len(nums)):
        if nums[i] + nums[j] == target:
            return [i, j]

indexed = sorted(enumerate(nums), key=lambda x: x[1])
l, r = 0, len(indexed) - 1
while l < r:
    s = indexed[l][1] + indexed[r][1]
    if s == target:
        return [indexed[l][0], indexed[r][0]]
    elif s < target:
        l += 1
    else:
        r -= 1
